import React from 'react';

const KPIStrip = ({ kpis }) => {
  const kpiConfig = [
    {
      label: 'Total Pipeline',
      value: `$${kpis.totalPipeline}B`,
      sub: `${kpis.pendingApprovals + kpis.approvedYTD} submissions`,
      color: 'teal'
    },
    {
      label: 'Revenue at Risk',
      value: kpis.revenueAtRisk != null ? `${kpis.revenueAtRisk}B` : `${kpis.criticalCount || 0} critical`,
      sub: kpis.criticalCount != null ? `${kpis.criticalCount} critical submissions` : 'Filtered view',
      color: 'red'
    },
    {
      label: 'Pending Approvals',
      value: kpis.pendingApprovals,
      sub: 'Active submissions',
      color: 'amber'
    },
    {
      label: 'Approved YTD',
      value: kpis.approvedYTD ?? '—',
      sub: 'Current year',
      color: 'green'
    },
    {
      label: 'Avg Cycle Time',
      value: kpis.avgCycleTime != null ? `${kpis.avgCycleTime}d` : '—',
      sub: kpis.crlCount != null && kpis.crlCount > 0 ? `${kpis.crlCount} CRLs received` : 'On track',
      color: 'blue'
    }
  ];

  return (
    <div className="kpi-strip">
      {kpiConfig.map((kpi, index) => (
        <div key={index} className={`kpi ${kpi.color}`}>
          <div className="kpi-label">{kpi.label}</div>
          <div className="kpi-value">{kpi.value}</div>
          <div className="kpi-sub">{kpi.sub}</div>
        </div>
      ))}
    </div>
  );
};

export default KPIStrip;
